from operator import add, mul, sub, truediv


class Pair:
    def __init__(self, first, second):
        self.first = first
        self.second = second

    def map(self, fn):
        return Pair(fn(self.first), self.second.map(fn))


class Nil:
    def map(self, fn):
        return self


nil = Nil()


def as_scheme_list(*values):
    result = nil
    for value in reversed(values):
        result = Pair(value, result)
    return result


def reduce_pair(fn, args, start):
    total = start
    current = args
    while current is not nil:
        total = fn(total, current.first)
        current = current.second
    return total


def calc_apply(operator, args):
    if operator == "+":
        return reduce_pair(add, args, 0)
    if operator == "*":
        return reduce_pair(mul, args, 1)
    if operator == "-":
        if args.second is nil:
            return -args.first
        return reduce_pair(sub, args.second, args.first)
    if operator == "/":
        if args.second is nil:
            return 1 / args.first
        return reduce_pair(truediv, args.second, args.first)
    raise TypeError(operator + " is an unknown operator")


def calc_eval(exp):
    if isinstance(exp, (int, float)):
        return exp
    if isinstance(exp, Pair):
        arguments = exp.second.map(calc_eval)
        return calc_apply(exp.first, arguments)
    raise TypeError(str(exp) + " is not a number or call expression")


left = Pair("+", as_scheme_list(1, 2))
right = Pair("+", as_scheme_list(2, 3))
expression = Pair("*", as_scheme_list(left, right))
print(calc_eval(expression))
print(calc_apply("+", as_scheme_list(1, 2, 3)))
print(calc_apply("*", nil))
